// 202_SOLAR_BACKUP_CARGAS_CRITICAS
const cargas = $input.item.json.cargas_criticas || [];
let potencia_critica_simultanea_kw = 0;
let energia_critica_kwh = 0;
let tem_motores = false;

for (const carga of cargas) {
    const pot_kw = carga.potencia_w / 1000;
    const energia = pot_kw * carga.horas_uso * carga.quantidade;
    energia_critica_kwh += energia;
    potencia_critica_simultanea_kw += (pot_kw * carga.quantidade);

    if (carga.descricao.toLowerCase().match(/(bomba|motor|elevador|compressor)/)) {
        tem_motores = true;
    }
}

$input.item.json.energia_critica_kwh = energia_critica_kwh;
$input.item.json.potencia_critica_simultanea_kw = potencia_critica_simultanea_kw;
$input.item.json.tem_motores = tem_motores;

return $input.item;
